import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Icon,
  Spacer,
} from '@ggui-ai/design/primitives';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  return (
    <Card padding={0} shadow="md" radius="xl" border>
      {/* Header Section */}
      <Box
        padding={24}
        background="linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7) 0%, var(--ggui-color-primary-800, #075985) 100%)"
        borderRadius="var(--ggui-shape-radius-xl) var(--ggui-shape-radius-xl) 0 0"
      >
        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-surface, #ffffff)">
              {city}
            </Heading>
            <Text variant="body" color="var(--ggui-color-primary-100, #e0f2fe)">
              {new Date().toLocaleDateString(undefined, {
                weekday: 'long',
                month: 'long',
                day: 'numeric',
              })}
            </Text>
          </Stack>
          <Box style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}>
            {/* Logic to determine icon could go here, but using a placeholder or emoji based on condition */}
            {condition.toLowerCase().includes('sun') ? '☀️' : '☁️'}
          </Box>
        </Stack>

        <Spacer size={24} />

        <Stack direction="horizontal" align="center" justify="between">
          <Stack gap={0}>
            <div style={{ display: 'flex', alignItems: 'flex-start' }}>
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 72px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'white',
                  lineHeight: 1,
                }}
              >
                {temperature}
              </span>
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                  color: 'white',
                  marginTop: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                °{unit}
              </span>
            </div>
            <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-surface, #ffffff)">
              {condition}
            </Text>
          </Stack>

          <Stack gap={12} align="end">
            <Stack direction="horizontal" gap={8} align="center">
              <Icon name="settings" size={16} color="var(--ggui-color-primary-200, #bae6fd)" />
              <Text variant="bodySmall" color="var(--ggui-color-surface, #ffffff)">
                Humidity: {humidity}%
              </Text>
            </Stack>
            <Stack direction="horizontal" gap={8} align="center">
              <Icon name="plus" size={16} color="var(--ggui-color-primary-200, #bae6fd)" />
              <Text variant="bodySmall" color="var(--ggui-color-surface, #ffffff)">
                Wind: {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Stack>
      </Box>

      {/* Forecast Section */}
      <Box padding={20}>
        <Text
          variant="overline"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}
        >
          5-Day Forecast
        </Text>
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.slice(0, 5).map((item, index) => (
            <Stack key={index} gap={8} align="center" style={{ flex: 1 }}>
              <Text variant="label" weight="semibold">
                {item.day}
              </Text>
              <div style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }}>
                {item.icon}
              </div>
              <Stack gap={2} align="center">
                <Text variant="bodySmall" weight="bold">
                  {item.high}°
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Box>
    </Card>
  );
}
